SELECT 
  FROM emp.tn_emp_risk r
 WHERE r.emp_plan_id = #{empPlanId}
   AND r.risk_sn     = #{sn}
   AND NOW() BETWEEN r.use_bgng_dt AND r.use_end_dt

SELECT COALESCE(MAX(risk_sn), 0) + 1
  FROM emp.tn_emp_risk
 WHERE emp_plan_id = #{empPlanId}

mapper.update:
UPDATE emp.tn_emp_risk
   SET risk_desc        = #{riskDesc},
       ctrl_actv        = #{ctrlActv},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE emp_plan_id = #{empPlanId}
   AND risk_sn     = #{riskSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE emp.tn_emp_risk
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id = #{empPlanId}
   AND risk_sn     = #{sn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
